{
  "sentences": [
    {
      "text": "不好意思，我想要一杯小杯的拿鐵。",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de0 na2 tie3.",
      "translation_en": "Excuse me, I would like a small latte.",
      "translation_ko": "실례합니다, 작은 사이즈의 라떼 한 잔을 원합니다."
    },
    {
      "text": "不好意思，麻煩給我兩杯紅茶，一杯去冰，一杯少冰。",
      "pinyin": "Bù hǎo yì si, má fan gěi wǒ liǎng bēi hóng chá, yī bēi qù bīng, yī bēi shǎo bīng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ma2 fan0 gei3 wo3 liang3 bei1 hong2 cha2, yi1 bei1 qu4 bing1, yi1 bei1 shao3 bing1.",
      "translation_en": "Excuse me, please give me two cups of black tea, one with no ice and one with less ice.",
      "translation_ko": "실례합니다, 홍차 두 잔 주세요. 하나는 얼음 빼고, 하나는 얼음 적게 해 주세요."
    },
    {
      "text": "不好意思，請問這個價錢是多少？",
      "pinyin": "Bù hǎo yì si, qǐng wèn zhè ge jià qián shì duō shǎo?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 wen4 zhe4 ge0 jia4 qian2 shi4 duo1 shao3?",
      "translation_en": "Excuse me, how much is this?",
      "translation_ko": "실례합니다, 이 가격이 얼마인가요?"
    },
    {
      "text": "不好意思，我要一杯豆漿，半糖，外帶。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi dòu jiāng, bàn táng, wài dài.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 dou4 jiang1, ban4 tang2, wai4 dai4.",
      "translation_en": "Excuse me, I'd like a cup of soy milk, half sugar, to go.",
      "translation_ko": "실례합니다, 두유 한 잔, 당도 반으로 해서 포장해 주세요."
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, can you add boba for me?",
      "translation_ko": "실례합니다, 펄을 추가해 주시겠어요?"
    },
    {
      "text": "不好意思，我要一杯綠茶，微糖，少冰，內用。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi lǜ chá, wēi táng, shǎo bīng, nèi yòng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 lü4 cha2, wei1 tang2, shao3 bing1, nei4 yong4.",
      "translation_en": "Excuse me, I'd like a cup of green tea, low sugar, less ice, for here.",
      "translation_ko": "실례합니다, 녹차 한 잔, 당도 적게, 얼음 적게 해서 매장에서 먹겠습니다."
    },
    {
      "text": "不好意思，麻煩給我一個袋子。",
      "pinyin": "Bù hǎo yì si, má fan gěi wǒ yī ge dài zi.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ma2 fan0 gei3 wo3 yi1 ge0 dai4 zi0.",
      "translation_en": "Excuse me, please give me a bag.",
      "translation_ko": "실례합니다, 봉투 하나 주세요."
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不太清楚。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Wǒ tīng bù tài qīng chu.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? Wo3 ting1 bu4 tai4 qing1 chu0.",
      "translation_en": "Excuse me, can you say that again? I didn't hear clearly.",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주시겠어요? 잘 안 들렸어요."
    },
    {
      "text": "不好意思，我要一杯大杯的拿鐵，正常甜，加珍珠，外帶。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi dà bēi de ná tiě, zhèng cháng tián, jiā zhēn zhū, wài dài.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 da4 bei1 de0 na2 tie3, zheng4 chang2 tian2, jia1 zhen1 zhu1, wai4 dai4.",
      "translation_en": "Excuse me, I'd like a large latte, regular sweetness, with boba, to go.",
      "translation_ko": "실례합니다, 큰 사이즈 라떼 한 잔, 당도 보통, 펄 추가해서 포장해 주세요."
    },
    {
      "text": "不好意思，請問你們有賣冰的拿鐵嗎？",
      "pinyin": "Bù hǎo yì si, qǐng wèn nǐ men yǒu mài bīng de ná tiě ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 wen4 ni3 men0 you3 mai4 bing1 de0 na2 tie3 ma0?",
      "translation_en": "Excuse me, do you sell iced lattes?",
      "translation_ko": "실례합니다, 아이스 라떼를 판매하시나요?"
    }
  ]
}
